function add (uint a, uint b) internal pure returns (uint c)

    {
        c = a + b; require (c > = a);
    }

function sub (uint a, uint b) internal pure returns (uint c)

    {
        require (b < = a); c = a - b;
    }

function mul (uint a, uint b) internal pure returns (uint c)

    {
        c = a * b; require (a = = 0 | | c / a = = b);
    }

function div (uint a, uint b) internal pure returns (uint c)

    {
        require (b > 0); c = a / b;
    }

function limitLessThan (uint a, uint b) internal pure returns (uint c)

    {
        if (a > b) return b; return a;
    }

function Owned () public

    {
        owner = msg.sender;
    }

function transferOwnership (address _newOwner) public onlyOwner

    {
        newOwner = _newOwner;
    }

function acceptOwnership () public

    {
        require (msg.sender = = newOwner); OwnershipTransferred (owner, newOwner); owner = newOwner; newOwner = address (0);
    }

function _drsebitoken () public onlyOwner

    {
        symbol = "SEBI"; name = "Dr Sebi Token"; decimals = 8; _totalSupply = 100000000 * 10 * * uint (decimals); if (locked) revert (); locked = true; tokensMinted = 0; rewardEra = 0; maxSupplyForEra = _totalSupply.div (2); miningTarget = _MAXIMUM_TARGET
          ; latestDifficultyPeriodStarted = block.number; _startNewMiningEpoch ();
    }

function mint (uint256 nonce, bytes32 challenge_digest) public returns (bool success)

    {
        bytes32 digest = keccak256 (challengeNumber, msg.sender, nonce); if (digest ! = challenge_digest) revert (); if (uint256 (digest) > miningTarget) revert (); bytes32 solution = solutionForChallenge [challengeNumber]; solutionForChallenge [
          challengeNumber] = digest; if (solution ! = 0x0) revert (); uint reward_amount = getMiningReward (); balances [msg.sender] = balances [msg.sender].add (reward_amount); tokensMinted = tokensMinted.add (reward_amount); assert (tokensMinted < =
          maxSupplyForEra); lastRewardTo = msg.sender; lastRewardAmount = reward_amount; lastRewardEthBlockNumber = block.number; _startNewMiningEpoch (); Mint (msg.sender, reward_amount, epochCount, challengeNumber); return true;
    }

function _startNewMiningEpoch () internal

    {
        if (tokensMinted.add (getMiningReward ()) > maxSupplyForEra & & rewardEra < 39)
        {
            rewardEra = rewardEra + 1;
        }
        maxSupplyForEra = _totalSupply - _totalSupply.div (2 * * (rewardEra + 1)); epochCount = epochCount.add (1); if (epochCount % _BLOCKS_PER_READJUSTMENT = = 0)
        {
            _reAdjustDifficulty ();
        }
        challengeNumber = block.blockhash (block.number - 1);
    }

function _reAdjustDifficulty () internal

    {
        uint ethBlocksSinceLastDifficultyPeriod = block.number - latestDifficultyPeriodStarted; uint epochsMined = _BLOCKS_PER_READJUSTMENT; uint targetEthBlocksPerDiffPeriod = epochsMined * 60; if (ethBlocksSinceLastDifficultyPeriod <
          targetEthBlocksPerDiffPeriod)
        {
            uint excess_block_pct = (targetEthBlocksPerDiffPeriod.mul (100)).div (ethBlocksSinceLastDifficultyPeriod); uint excess_block_pct_extra = excess_block_pct.sub (100).limitLessThan (1000); miningTarget = miningTarget.sub (miningTarget.div (2000).
              mul (excess_block_pct_extra));
        }
        else
        {
            uint shortage_block_pct = (ethBlocksSinceLastDifficultyPeriod.mul (100)).div (targetEthBlocksPerDiffPeriod); uint shortage_block_pct_extra = shortage_block_pct.sub (100).limitLessThan (1000); miningTarget = miningTarget.add (miningTarget.div (
              2000).mul (shortage_block_pct_extra));
        }
        latestDifficultyPeriodStarted = block.number; if (miningTarget < _MINIMUM_TARGET)
        {
            miningTarget = _MINIMUM_TARGET;
        }
        if (miningTarget > _MAXIMUM_TARGET)
        {
            miningTarget = _MAXIMUM_TARGET;
        }

    }

function getChallengeNumber () public constant returns (bytes32)

    {
        return challengeNumber;
    }

function getMiningDifficulty () public constant returns (uint)

    {
        return _MAXIMUM_TARGET.div (miningTarget);
    }

function getMiningTarget () public constant returns (uint)

    {
        return miningTarget;
    }

function getMiningReward () public constant returns (uint)

    {
        return (50 * 10 * uint (decimals)).div (2 * rewardEra);
    }

function getMintDigest (uint256 nonce, bytes32 challenge_digest, bytes32 challenge_number) public view returns (bytes32 digesttest)

    {
        bytes32 digest = keccak256 (challenge_number, msg.sender, nonce); return digest;
    }

function checkMintSolution (uint256 nonce, bytes32 challenge_digest, bytes32 challenge_number, uint testTarget) public view returns (bool success)

    {
        bytes32 digest = keccak256 (challenge_number, msg.sender, nonce); if (uint256 (digest) > testTarget) revert (); return (digest = = challenge_digest);
    }

function totalSupply () public constant returns (uint)

    {
        return _totalSupply - balances [address (0)];
    }

function balanceOf (address tokenOwner) public constant returns (uint balance)

    {
        return balances [tokenOwner];
    }

function transfer (address to, uint tokens) public returns (bool success)

    {
        balances [msg.sender] = balances [msg.sender].sub (tokens); balances [to] = balances [to].add (tokens); Transfer (msg.sender, to, tokens); return true;
    }

function approve (address spender, uint tokens) public returns (bool success)

    {
        allowed [msg.sender] [spender] = tokens; Approval (msg.sender, spender, tokens); return true;
    }

function transferFrom (address from, address to, uint tokens) public returns (bool success)

    {
        balances [from] = balances [from].sub (tokens); allowed [from] [msg.sender] = allowed [from] [msg.sender].sub (tokens); balances [to] = balances [to].add (tokens); Transfer (from, to, tokens); return true;
    }

function allowance (address tokenOwner, address spender) public constant returns (uint remaining)

    {
        return allowed [tokenOwner] [spender];
    }

function approveAndCall (address spender, uint tokens, bytes data) public returns (bool success)

    {
        allowed [msg.sender] [spender] = tokens; Approval (msg.sender, spender, tokens); ApproveAndCallFallBack (spender).receiveApproval (msg.sender, tokens, this, data); return true;
    }

function () public payable

    {
        revert ();
    }

function transferAnyERC20Token (address tokenAddress, uint tokens) public onlyOwner returns (bool success)

    {
        return ERC20Interface (tokenAddress).transfer (owner, tokens);
    }

function logMarketCreated (bytes32 _topic, string _description, string _extraInfo, IUniverse _universe, address _market, address _marketCreator, bytes32 [] _outcomes, int256 _minPrice, int256 _maxPrice, IMarket.MarketType _marketType) public returns (bool
  )
    ;

function logOrderFilled (IUniverse _universe, address _shareToken, address _filler, bytes32 _orderId, uint256 _numCreatorShares, uint256 _numCreatorTokens, uint256 _numFillerShares, uint256 _numFillerTokens, uint256 _marketCreatorFees, uint256
  _reporterFees, uint256 _amountFilled, bytes32 _tradeGroupId) public returns (bool)
    ;

function Controlled () public

    {
        controller = IController (msg.sender);
    }

function getController () public view returns (IController)

    {
        return controller;
    }

function setController (IController _controller) public onlyControllerCaller returns (bool)

    {
        controller = _controller; return true;
    }

function createGenesisUniverse () public returns (IUniverse)

    {
        return createUniverse (IUniverse (0), bytes32 (0), new uint256 [] (0), false);
    }

function createChildUniverse (bytes32 _parentPayoutDistributionHash, uint256 [] _parentPayoutNumerators, bool _parentInvalid) public returns (IUniverse)

    {
        IUniverse _parentUniverse = IUniverse (msg.sender); require (isKnownUniverse (_parentUniverse)); return createUniverse (_parentUniverse, _parentPayoutDistributionHash, _parentPayoutNumerators, _parentInvalid);
    }

function createUniverse (IUniverse _parentUniverse, bytes32 _parentPayoutDistributionHash, uint256 [] _parentPayoutNumerators, bool _parentInvalid) private returns (IUniverse)

    {
        UniverseFactory _universeFactory = UniverseFactory (controller.lookup ("UniverseFactory")); IUniverse _newUniverse = _universeFactory.createUniverse (controller, _parentUniverse, _parentPayoutDistributionHash); universes [_newUniverse] = true;
          UniverseCreated (_parentUniverse, _newUniverse, _parentPayoutNumerators, _parentInvalid); return _newUniverse;
    }

function isKnownUniverse (IUniverse _universe) public view returns (bool)

    {
        return universes [_universe];
    }

function isKnownCrowdsourcer (IDisputeCrowdsourcer _crowdsourcer) public view returns (bool)

    {
        return crowdsourcers [_crowdsourcer];
    }

function disputeCrowdsourcerCreated (IUniverse _universe, address _market, address _disputeCrowdsourcer, uint256 [] _payoutNumerators, uint256 _size, bool _invalid) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForMarket (IMarket (msg.sender))); crowdsourcers [_disputeCrowdsourcer] = true; DisputeCrowdsourcerCreated (_universe, _market, _disputeCrowdsourcer, _payoutNumerators, _size,
          _invalid); return true;
    }

function trustedTransfer (ERC20 _token, address _from, address _to, uint256 _amount) public onlyWhitelistedCallers returns (bool)

    {
        require (_amount > 0); require (_token.transferFrom (_from, _to, _amount)); return true;
    }

function logMarketCreated (bytes32 _topic, string _description, string _extraInfo, IUniverse _universe, address _market, address _marketCreator, bytes32 [] _outcomes, int256 _minPrice, int256 _maxPrice, IMarket.MarketType _marketType) public returns (bool
  )

    {
        require (isKnownUniverse (_universe)); require (_universe = = IUniverse (msg.sender)); MarketCreated (_topic, _description, _extraInfo, _universe, _market, _marketCreator, _outcomes, _universe.getOrCacheMarketCreationCost (), _minPrice, _maxPrice,
          _marketType); return true;
    }

function logMarketCreated (bytes32 _topic, string _description, string _extraInfo, IUniverse _universe, address _market, address _marketCreator, int256 _minPrice, int256 _maxPrice, IMarket.MarketType _marketType) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe = = IUniverse (msg.sender)); MarketCreated (_topic, _description, _extraInfo, _universe, _market, _marketCreator, new bytes32 [] (0), _universe.getOrCacheMarketCreationCost (), _minPrice,
          _maxPrice, _marketType); return true;
    }

function logInitialReportSubmitted (IUniverse _universe, address _reporter, address _market, uint256 _amountStaked, bool _isDesignatedReporter, uint256 [] _payoutNumerators, bool _invalid) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForMarket (IMarket (msg.sender))); InitialReportSubmitted (_universe, _reporter, _market, _amountStaked, _isDesignatedReporter, _payoutNumerators, _invalid); return true;
    }

function logDisputeCrowdsourcerContribution (IUniverse _universe, address _reporter, address _market, address _disputeCrowdsourcer, uint256 _amountStaked) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForMarket (IMarket (msg.sender))); DisputeCrowdsourcerContribution (_universe, _reporter, _market, _disputeCrowdsourcer, _amountStaked); return true;
    }

function logDisputeCrowdsourcerCompleted (IUniverse _universe, address _market, address _disputeCrowdsourcer) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForMarket (IMarket (msg.sender))); DisputeCrowdsourcerCompleted (_universe, _market, _disputeCrowdsourcer); return true;
    }

function logInitialReporterRedeemed (IUniverse _universe, address _reporter, address _market, uint256 _amountRedeemed, uint256 _repReceived, uint256 _reportingFeesReceived, uint256 [] _payoutNumerators) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForReportingParticipant (IReportingParticipant (msg.sender))); InitialReporterRedeemed (_universe, _reporter, _market, _amountRedeemed, _repReceived, _reportingFeesReceived,
          _payoutNumerators); return true;
    }

function logDisputeCrowdsourcerRedeemed (IUniverse _universe, address _reporter, address _market, uint256 _amountRedeemed, uint256 _repReceived, uint256 _reportingFeesReceived, uint256 [] _payoutNumerators) public returns (bool)

    {
        IDisputeCrowdsourcer _disputeCrowdsourcer = IDisputeCrowdsourcer (msg.sender); require (isKnownCrowdsourcer (_disputeCrowdsourcer)); DisputeCrowdsourcerRedeemed (_universe, _reporter, _market, _disputeCrowdsourcer, _amountRedeemed, _repReceived,
          _reportingFeesReceived, _payoutNumerators); return true;
    }

function logReportingParticipantDisavowed (IUniverse _universe, IMarket _market) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForReportingParticipant (IReportingParticipant (msg.sender))); ReportingParticipantDisavowed (_universe, _market, msg.sender); return true;
    }

function logMarketParticipantsDisavowed (IUniverse _universe) public returns (bool)

    {
        require (isKnownUniverse (_universe)); IMarket _market = IMarket (msg.sender); require (_universe.isContainerForMarket (_market)); MarketParticipantsDisavowed (_universe, _market); return true;
    }

function logFeeWindowRedeemed (IUniverse _universe, address _reporter, uint256 _amountRedeemed, uint256 _reportingFeesReceived) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeWindow (IFeeWindow (msg.sender))); FeeWindowRedeemed (_universe, _reporter, msg.sender, _amountRedeemed, _reportingFeesReceived); return true;
    }

function logMarketFinalized (IUniverse _universe) public returns (bool)

    {
        require (isKnownUniverse (_universe)); IMarket _market = IMarket (msg.sender); require (_universe.isContainerForMarket (_market)); MarketFinalized (_universe, _market); return true;
    }

function logMarketMigrated (IMarket _market, IUniverse _originalUniverse) public returns (bool)

    {
        IUniverse _newUniverse = IUniverse (msg.sender); require (isKnownUniverse (_newUniverse)); MarketMigrated (_market, _originalUniverse, _newUniverse); return true;
    }

function logOrderCanceled (IUniverse _universe, address _shareToken, address _sender, bytes32 _orderId, Order.Types _orderType, uint256 _tokenRefund, uint256 _sharesRefund) public onlyWhitelistedCallers returns (bool)

    {
        OrderCanceled (_universe, _shareToken, _sender, _orderId, _orderType, _tokenRefund, _sharesRefund); return true;
    }

function logOrderCreated (Order.Types _orderType, uint256 _amount, uint256 _price, address _creator, uint256 _moneyEscrowed, uint256 _sharesEscrowed, bytes32 _tradeGroupId, bytes32 _orderId, IUniverse _universe, address _shareToken) public
  onlyWhitelistedCallers returns (bool)

    {
        OrderCreated (_orderType, _amount, _price, _creator, _moneyEscrowed, _sharesEscrowed, _tradeGroupId, _orderId, _universe, _shareToken); return true;
    }

function logOrderFilled (IUniverse _universe, address _shareToken, address _filler, bytes32 _orderId, uint256 _numCreatorShares, uint256 _numCreatorTokens, uint256 _numFillerShares, uint256 _numFillerTokens, uint256 _marketCreatorFees, uint256
  _reporterFees, uint256 _amountFilled, bytes32 _tradeGroupId) public onlyWhitelistedCallers returns (bool)

    {
        OrderFilled (_universe, _shareToken, _filler, _orderId, _numCreatorShares, _numCreatorTokens, _numFillerShares, _numFillerTokens, _marketCreatorFees, _reporterFees, _amountFilled, _tradeGroupId); return true;
    }

function logCompleteSetsPurchased (IUniverse _universe, IMarket _market, address _account, uint256 _numCompleteSets) public onlyWhitelistedCallers returns (bool)

    {
        CompleteSetsPurchased (_universe, _market, _account, _numCompleteSets); return true;
    }

function logCompleteSetsSold (IUniverse _universe, IMarket _market, address _account, uint256 _numCompleteSets) public onlyWhitelistedCallers returns (bool)

    {
        CompleteSetsSold (_universe, _market, _account, _numCompleteSets); return true;
    }

function logTradingProceedsClaimed (IUniverse _universe, address _shareToken, address _sender, address _market, uint256 _numShares, uint256 _numPayoutTokens, uint256 _finalTokenBalance) public onlyWhitelistedCallers returns (bool)

    {
        TradingProceedsClaimed (_universe, _shareToken, _sender, _market, _numShares, _numPayoutTokens, _finalTokenBalance); return true;
    }

function logUniverseForked () public returns (bool)

    {
        require (universes [msg.sender]); UniverseForked (msg.sender); return true;
    }

function logFeeWindowTransferred (IUniverse _universe, address _from, address _to, uint256 _value) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeWindow (IFeeWindow (msg.sender))); TokensTransferred (_universe, msg.sender, _from, _to, _value, TokenType.FeeWindow, 0); return true;
    }

function logReputationTokensTransferred (IUniverse _universe, address _from, address _to, uint256 _value) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.getReputationToken () = = IReputationToken (msg.sender)); TokensTransferred (_universe, msg.sender, _from, _to, _value, TokenType.ReputationToken, 0); return true;
    }

function logDisputeCrowdsourcerTokensTransferred (IUniverse _universe, address _from, address _to, uint256 _value) public returns (bool)

    {
        IDisputeCrowdsourcer _disputeCrowdsourcer = IDisputeCrowdsourcer (msg.sender); require (isKnownCrowdsourcer (_disputeCrowdsourcer)); TokensTransferred (_universe, msg.sender, _from, _to, _value, TokenType.DisputeCrowdsourcer, _disputeCrowdsourcer.
          getMarket ()); return true;
    }

function logShareTokensTransferred (IUniverse _universe, address _from, address _to, uint256 _value) public returns (bool)

    {
        require (isKnownUniverse (_universe)); IShareToken _shareToken = IShareToken (msg.sender); require (_universe.isContainerForShareToken (_shareToken)); TokensTransferred (_universe, msg.sender, _from, _to, _value, TokenType.ShareToken, _shareToken.
          getMarket ()); return true;
    }

function logReputationTokenBurned (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.getReputationToken () = = IReputationToken (msg.sender)); TokensBurned (_universe, msg.sender, _target, _amount, TokenType.ReputationToken, 0); return true;
    }

function logReputationTokenMinted (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.getReputationToken () = = IReputationToken (msg.sender)); TokensMinted (_universe, msg.sender, _target, _amount, TokenType.ReputationToken, 0); return true;
    }

function logShareTokenBurned (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); IShareToken _shareToken = IShareToken (msg.sender); require (_universe.isContainerForShareToken (_shareToken)); TokensBurned (_universe, msg.sender, _target, _amount, TokenType.ShareToken, _shareToken.
          getMarket ()); return true;
    }

function logShareTokenMinted (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); IShareToken _shareToken = IShareToken (msg.sender); require (_universe.isContainerForShareToken (_shareToken)); TokensMinted (_universe, msg.sender, _target, _amount, TokenType.ShareToken, _shareToken.
          getMarket ()); return true;
    }

function logFeeWindowBurned (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeWindow (IFeeWindow (msg.sender))); TokensBurned (_universe, msg.sender, _target, _amount, TokenType.FeeWindow, 0); return true;
    }

function logFeeWindowMinted (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeWindow (IFeeWindow (msg.sender))); TokensMinted (_universe, msg.sender, _target, _amount, TokenType.FeeWindow, 0); return true;
    }

function logDisputeCrowdsourcerTokensBurned (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        IDisputeCrowdsourcer _disputeCrowdsourcer = IDisputeCrowdsourcer (msg.sender); require (isKnownCrowdsourcer (_disputeCrowdsourcer)); TokensBurned (_universe, msg.sender, _target, _amount, TokenType.DisputeCrowdsourcer, _disputeCrowdsourcer.
          getMarket ()); return true;
    }

function logDisputeCrowdsourcerTokensMinted (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        IDisputeCrowdsourcer _disputeCrowdsourcer = IDisputeCrowdsourcer (msg.sender); require (isKnownCrowdsourcer (_disputeCrowdsourcer)); TokensMinted (_universe, msg.sender, _target, _amount, TokenType.DisputeCrowdsourcer, _disputeCrowdsourcer.
          getMarket ()); return true;
    }

function logFeeWindowCreated (IFeeWindow _feeWindow, uint256 _id) public returns (bool)

    {
        require (universes [msg.sender]); FeeWindowCreated (msg.sender, _feeWindow, _feeWindow.getStartTime (), _feeWindow.getEndTime (), _id); return true;
    }

function logFeeTokenTransferred (IUniverse _universe, address _from, address _to, uint256 _value) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeToken (IFeeToken (msg.sender))); TokensTransferred (_universe, msg.sender, _from, _to, _value, TokenType.FeeToken, 0); return true;
    }

function logFeeTokenBurned (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeToken (IFeeToken (msg.sender))); TokensBurned (_universe, msg.sender, _target, _amount, TokenType.FeeToken, 0); return true;
    }

function logFeeTokenMinted (IUniverse _universe, address _target, uint256 _amount) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForFeeToken (IFeeToken (msg.sender))); TokensMinted (_universe, msg.sender, _target, _amount, TokenType.FeeToken, 0); return true;
    }

function logTimestampSet (uint256 _newTimestamp) public returns (bool)

    {
        require (msg.sender = = controller.lookup ("Time")); TimestampSet (_newTimestamp); return true;
    }

function logInitialReporterTransferred (IUniverse _universe, IMarket _market, address _from, address _to) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForMarket (_market)); require (msg.sender = = _market.getInitialReporterAddress ()); InitialReporterTransferred (_universe, _market, _from, _to); return true;
    }

function logMarketTransferred (IUniverse _universe, address _from, address _to) public returns (bool)

    {
        require (isKnownUniverse (_universe)); IMarket _market = IMarket (msg.sender); require (_universe.isContainerForMarket (_market)); MarketTransferred (_universe, _market, _from, _to); return true;
    }

function logMarketMailboxTransferred (IUniverse _universe, IMarket _market, address _from, address _to) public returns (bool)

    {
        require (isKnownUniverse (_universe)); require (_universe.isContainerForMarket (_market)); require (IMailbox (msg.sender) = = _market.getMarketCreatorMailbox ()); MarketMailboxTransferred (_universe, _market, msg.sender, _from, _to); return true;
    }

function logEscapeHatchChanged (bool _isOn) public returns (bool)

    {
        require (msg.sender = = address (controller)); EscapeHatchChanged (_isOn); return true;
    }

function createUniverse (IController _controller, IUniverse _parentUniverse, bytes32 _parentPayoutDistributionHash) public returns (IUniverse)

    {
        Delegator _delegator = new Delegator (_controller, "Universe"); IUniverse _universe = IUniverse (_delegator); _universe.initialize (_parentUniverse, _parentPayoutDistributionHash); return _universe;
    }

function Delegator (IController _controller, bytes32 _controllerLookupName) public

    {
        controller = _controller; controllerLookupName = _controllerLookupName;
    }

function () external payable

    {
        if (controllerLookupName = = 0)
        {
            return;
        }
        address _target = controller.lookup (controllerLookupName); assembly {let _calldataMemoryOffset : = mload (0x40) let _size : = and (add (calldatasize, 0x1f), not (0x1f)) mstore (0x40, add (_calldataMemoryOffset, _size)) calldatacopy (
          _calldataMemoryOffset, 0x0, calldatasize) let _retval : = delegatecall (gas, _target, _calldataMemoryOffset, calldatasize, 0, 0) switch _retval case 0 {revert (0, 0)} default {let _returndataMemoryOffset : = mload (0x40) mstore (0x40, add (
          _returndataMemoryOffset, returndatasize)) returndatacopy (_returndataMemoryOffset, 0x0, returndatasize) return (_returndataMemoryOffset, returndatasize)}}
    }

function endInitialization () internal beforeInitialized returns (bool)

    {
        initialized = true; return true;
    }

function getInitialized () public view returns (bool)

    {
        return initialized;
    }

function mul (uint256 a, uint256 b) internal pure returns (uint256)

    {
        uint256 c = a * b; require (a = = 0 | | c / a = = b); return c;
    }

function div (uint256 a, uint256 b) internal pure returns (uint256)

    {
        uint256 c = a / b; return c;
    }

function sub (uint256 a, uint256 b) internal pure returns (uint256)

    {
        require (b < = a); return a - b;
    }

function add (uint256 a, uint256 b) internal pure returns (uint256)

    {
        uint256 c = a + b; require (c > = a); return c;
    }

function min (uint256 a, uint256 b) internal pure returns (uint256)

    {
        if (a < = b)
        {
            return a;
        }
        else
        {
            return b;
